          '7': { text: 'Jestem dobry/a w budowaniu lub naprawianiu rzeczy r\u0119kami.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
