          '9': { text: 'Ceni\u0119 kreatywno\u015b\u0107 i mo\u017cliwo\u015b\u0107 wyra\u017cania siebie w pracy.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
          '10': { text: 'Lubi\u0119 bezpo\u015brednio pracowa\u0107 z lud\u017ami w roli wspieraj\u0105cej.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
          '11': { text: 'Lubi\u0119 przekonywa\u0107 innych lub sprzedawa\u0107 im pomys\u0142y.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
          '12': { text: 'Lubi\u0119 pracowa\u0107 z danymi, liczbami i szczeg\u00f3\u0142owymi rejestrami.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
          '13': { text: 'Chcia\u0142bym/chcia\u0142abym pracowa\u0107 na zewn\u0105trz i wykonywa\u0107 prac\u0119 fizyczn\u0105.', options: ['Zupe\u0142nie do mnie nie pasuje', 'Troch\u0119 do mnie pasuje', 'Do\u015b\u0107 do mnie pasuje', 'Bardzo do mnie pasuje'] },
