      enneagram: {
        name: 'Wska\u017anik typu Enneagramu',
        tagline: 'Dziewi\u0119\u0107 archetyp\u00f3w osobowo\u015bci',
        description: 'Enneagram opisuje dziewi\u0119\u0107 powi\u0105zanych ze sob\u0105 typ\u00f3w osobowo\u015bci. Ka\u017cdy typ odzwierciedla unikalne g\u0142\u00f3wne motywacje, l\u0119ki i wzorce postrzegania \u015bwiata oraz relacji z innymi. To narz\u0119dzie do samopoznania i rozwoju osobistego.',
        questions: {
          '1': { text: 'Mam silne poczucie dobra i z\u0142a i czuj\u0119 si\u0119 nap\u0119dzany/a do \u017cycia zgodnego ze swoimi zasadami.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '2': { text: 'Cz\u0119sto dostrzegam, co jest z\u0142e lub niedoskona\u0142e w sytuacjach i czuj\u0119 potrzeb\u0119 naprawy.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '3': { text: 'Stawiam sobie bardzo wysokie wymagania i krytykuj\u0119 si\u0119, gdy ich nie spe\u0142niam.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '4': { text: 'Mam tendencj\u0119 do skupiania si\u0119 na potrzebach innych bardziej ni\u017c na swoich.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '5': { text: 'Odczuwam g\u0142\u0119bok\u0105 satysfakcj\u0119, gdy bliscy czuj\u0105 si\u0119 przeze mnie wspierani.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '6': { text: 'Mog\u0119 mie\u0107 trudno\u015bci z proszeniem o pomoc, bo wol\u0119 by\u0107 osob\u0105 daj\u0105c\u0105.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '7': { text: 'Jestem silnie zmotywowany/a do sukcesu i chc\u0119 by\u0107 postrzegany/a jako kompetentny/a i wybitny/a.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '8': { text: 'Dostosowuj\u0119 sw\u00f3j wizerunek do sytuacji \u2014 wiem, jak zrobi\u0107 dobre wra\u017cenie.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '9': { text: 'Osi\u0105ganie cel\u00f3w jest centralnym elementem mojego poczucia warto\u015bci.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '10': { text: 'Cz\u0119sto czuj\u0119, \u017ce jestem fundamentalnie inny/a od wi\u0119kszo\u015bci ludzi.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '11': { text: 'Mam bogate wewn\u0119trzne \u017cycie emocjonalne i odczuwam rzeczy bardzo g\u0142\u0119boko.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '12': { text: 'Silnie pragn\u0119 g\u0142\u0119bokiego sensu i autentycznej ekspresji siebie.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '13': { text: 'Wol\u0119 obserwowa\u0107 i rozumie\u0107 sytuacj\u0119 przed zaanga\u017cowaniem si\u0119.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '14': { text: 'Starannie chroni\u0119 swoj\u0105 energi\u0119 i prywatn\u0105 przestrze\u0144.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '15': { text: 'Uwa\u017cam, \u017ce my\u015blenie i wiedza to moje najcenniejsze zasoby.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '16': { text: 'Jestem lojalny/a i niezawodny/a \u2014 ludzie mog\u0105 na mnie liczy\u0107.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '17': { text: 'Cz\u0119sto my\u015bl\u0119 o najgorszych scenariuszach, \u017ceby si\u0119 przygotowa\u0107 na problemy.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '18': { text: 'Musz\u0119 czu\u0107 zaufanie do kogo\u015b lub czego\u015b, zanim si\u0119 w pe\u0142ni zaanga\u017cuj\u0119.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '19': { text: 'Uwielbiam nowe do\u015bwiadczenia, pomys\u0142y i mo\u017cliwo\u015bci.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '20': { text: 'Mam tendencj\u0119 do szybkiego przeskakiwania z jednej ekscytuj\u0105cej rzeczy do nast\u0119pnej.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '21': { text: 'Trudno mi d\u0142ugo znosi\u0107 dyskomfort lub nud\u0119.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '22': { text: 'Ceni\u0119 si\u0142\u0119, uczciwo\u015b\u0107 i bezpo\u015brednio\u015b\u0107 \u2014 nie znosz\u0119 s\u0142abo\u015bci i pozor\u00f3w.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '23': { text: 'Naturalnie przejmuj\u0119 przyw\u00f3dztwo i chroni\u0119 ludzi, na kt\u00f3rych mi zale\u017cy.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '24': { text: 'Nie unikam konfliktu, je\u015bli wierz\u0119, \u017ce mam racj\u0119.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '25': { text: 'Jestem spokojny/a i potrafi\u0119 dostrzec ka\u017cd\u0105 stron\u0119 sprawy.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '26': { text: 'Lubi\u0119 harmoni\u0119 i staram si\u0119 unika\u0107 konflikt\u00f3w, kiedy tylko to mo\u017cliwe.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] },
          '27': { text: 'Zdarza mi si\u0119 traci\u0107 z oczu w\u0142asne priorytety, dostosowuj\u0105c si\u0119 do innych.', options: ['Niepodobne do mnie', 'Troch\u0119 jak ja', 'Do\u015b\u0107 jak ja', 'Bardzo jak ja'] }
        }
      },
