          '23': { text: 'Je\u015bli przeciwie\u0144stwem czarnego jest bia\u0142y, a przeciwie\u0144stwem g\u00f3ry jest d\u00f3\u0142, to przeciwie\u0144stwo \u201eb\u0142\u0119dnego\u201d to ___?', options: ['Lewy', 'Prawy', 'Prawid\u0142owy', 'B\u0142\u0119dny'] },
