          '9': { text: 'Kt\u00f3re z poni\u017cszych nale\u017cy do innej kategorii?\nMars, Neptun, Saturn, Ksi\u0119\u017cyc', options: ['Mars', 'Neptun', 'Saturn', 'Ksi\u0119\u017cyc'] },
          '10': { text: 'Prawid\u0142owe grupowanie:\nOrze\u0142, \u0141oso\u015b, Wieloryb, Nietoperz', options: ['Wszystkie s\u0105 zwierz\u0119tami', 'Orze\u0142 i nietoperz to ptaki; \u0142oso\u015b i wieloryb to ryby', 'Orze\u0142 i nietoperz maj\u0105 skrzyd\u0142a; \u0142oso\u015b i wieloryb \u017cyj\u0105 w wodzie', '\u0141oso\u015b i wieloryb s\u0105 wodne; orze\u0142, nietoperz, wieloryb to ssaki'] },
          '11': { text: 'Je\u015bli lekarz to kategoria \u201emedycyna\u201d, a nauczyciel to \u201eedukacja\u201d, to piel\u0119gniarka szkolna nale\u017cy do:', options: ['Tylko medycyna', 'Tylko edukacja', 'Obie', '\u017badna'] },
          '12': { text: 'Zebra najbardziej logicznie kojarzy si\u0119 z:', options: ['Ko\u0144 \u2014 podobna budowa cia\u0142a', 'Paski \u2014 najbardziej oczywista cecha', 'Afryka \u2014 siedlisko', 'Zale\u017cy od kontekstu pytania'] },
